+          <span className="ml-1 text-xs opacity-70">
+            ({Object.values(counts).reduce((a, b) => a + b, 0)})
+          </span>
+        )}
+      </Badge>
+
+      {categories.map((category) => (
+        <Badge
+          key={category}
+          variant={selected === category ? "default" : "outline"}
+          className={cn(
+            "cursor-pointer transition-all hover:scale-105 capitalize",
