+          )}
+          onClick={() => handleSelect(category)}
+        >
+          {category}
+          {counts?.[category] !== undefined && (
+            <span className="ml-1 text-xs opacity-70">({counts[category]})</span>
+          )}
+        </Badge>
+      ))}
+
+      {selected && (
+        <Button
+          variant="ghost"
+          size="sm"
+          className="h-6 px-2 text-xs text-zinc-500 hover:text-zinc-900 dark:hover:text-white"
